import { LoginForm } from "@/components/auth/login-form";
import Link from "next/link";

export default function AdminLoginPage() {
    return (
        <div className="min-h-screen flex flex-col items-center justify-center bg-gray-50 p-4">
            <div className="w-full max-w-md bg-white p-8 rounded-lg shadow-md">
                <div className="text-center mb-8">
                    <h1 className="text-2xl font-bold text-gray-900">Admin Login</h1>
                    <p className="text-gray-700">Manage your business inventory</p>
                </div>

                <LoginForm role="ADMIN" />

                <div className="mt-6 text-center text-sm text-gray-800">
                    Don't have an account?{" "}
                    <Link href="/signup" className="text-blue-600 hover:underline font-medium">
                        Register your business
                    </Link>
                </div>
            </div>
        </div>
    );
}

"use client";

import { useState } from "react";
import { useRouter } from "next/navigation";
import Link from "next/link";
import { Loader2, AlertCircle } from "lucide-react";

export default function SignupPage() {
    const router = useRouter();
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState("");

    const handleSubmit = async (e: React.FormEvent<HTMLFormElement>) => {
        e.preventDefault();
        setLoading(true);
        setError("");

        const formData = new FormData(e.currentTarget);
        const businessName = formData.get("businessName");
        const adminName = formData.get("adminName");
        const email = formData.get("email");
        const password = formData.get("password");

        try {
            const res = await fetch("/api/register", {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({ businessName, adminName, email, password }),
            });

            const data = await res.json();

            if (!res.ok) {
                throw new Error(data.error || "Registration failed");
            }

            router.push("/login/admin");
        } catch (err: any) {
            setError(err.message);
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="min-h-screen flex flex-col items-center justify-center bg-gray-50 p-4">
            <div className="w-full max-w-md bg-white p-8 rounded-lg shadow-md">
                <div className="text-center mb-8">
                    <h1 className="text-2xl font-bold text-gray-900">Register Business</h1>
                    <p className="text-gray-700">Start managing your inventory today</p>
                </div>

                <form onSubmit={handleSubmit} className="space-y-4">
                    {error && (
                        <div className="bg-red-50 text-red-500 p-3 rounded-md flex items-center gap-2 text-sm">
                            <AlertCircle size={16} />
                            {error}
                        </div>
                    )}

                    <div className="space-y-2">
                        <label className="text-sm font-medium text-gray-700">Business Name</label>
                        <input
                            name="businessName"
                            type="text"
                            required
                            className="w-full p-2 border rounded-md focus:ring-2 focus:ring-blue-500 outline-none"
                            placeholder="My Awesome Business"
                        />
                    </div>

                    <div className="space-y-2">
                        <label className="text-sm font-medium text-gray-700">Admin Name</label>
                        <input
                            name="adminName"
                            type="text"
                            required
                            className="w-full p-2 border rounded-md focus:ring-2 focus:ring-blue-500 outline-none"
                            placeholder="John Doe"
                        />
                    </div>

                    <div className="space-y-2">
                        <label className="text-sm font-medium text-gray-700">Email</label>
                        <input
                            name="email"
                            type="email"
                            required
                            className="w-full p-2 border rounded-md focus:ring-2 focus:ring-blue-500 outline-none"
                            placeholder="admin@example.com"
                        />
                    </div>

                    <div className="space-y-2">
                        <label className="text-sm font-medium text-gray-700">Password</label>
                        <input
                            name="password"
                            type="password"
                            required
                            className="w-full p-2 border rounded-md focus:ring-2 focus:ring-blue-500 outline-none"
                            placeholder="••••••••"
                        />
                    </div>

                    <button
                        type="submit"
                        disabled={loading}
                        className="w-full bg-blue-600 text-white py-2 rounded-md hover:bg-blue-700 transition-colors disabled:opacity-50 flex justify-center items-center gap-2"
                    >
                        {loading && <Loader2 className="animate-spin" size={16} />}
                        Create Account
                    </button>
                </form>

                <div className="mt-6 text-center text-sm text-gray-800">
                    Already have an account?{" "}
                    <Link href="/login/admin" className="text-blue-600 hover:underline font-medium">
                        Sign in
                    </Link>
                </div>
            </div>
        </div>
    );
}

"use client";

import { useEffect, useState } from "react";
import { Plus, Calendar, MapPin, User, Trash2 } from "lucide-react";

export default function OrdersPage() {
    const [orders, setOrders] = useState<any[]>([]);
    const [workers, setWorkers] = useState<any[]>([]);
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [editOrderId, setEditOrderId] = useState<string | null>(null);

    const fetchData = () => {
        fetch("/api/order")
            .then(async (res) => {
                if (res.ok) return res.json();
                throw new Error("Failed to fetch orders");
            })
            .then(setOrders)
            .catch(console.error);

        fetch("/api/worker")
            .then(async (res) => {
                if (res.ok) return res.json();
                throw new Error("Failed to fetch workers");
            })
            .then(setWorkers)
            .catch(console.error);
    };

    useEffect(() => {
        fetchData();
    }, []);

    const [selectedOrderId, setSelectedOrderId] = useState<string | null>(null);
    const selectedOrder = orders.find(o => o.id === selectedOrderId);

    return (
        <div className="space-y-6">
            <div className="flex items-center justify-between">
                <h1 className="text-2xl font-bold text-gray-900">Order Management</h1>
                <button
                    onClick={() => setIsModalOpen(true)}
                    className="bg-blue-600 text-white px-4 py-2 rounded-md flex items-center gap-2 hover:bg-blue-700"
                >
                    <Plus size={20} />
                    New Order
                </button>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                {orders.map((order) => (
                    <div key={order.id} className="bg-white p-6 rounded-lg shadow-sm border border-gray-200">
                        <div className="flex justify-between items-start mb-4">
                            <div>
                                <h3 className="font-bold text-lg text-gray-900">{order.orderName}</h3>
                                <p className="text-sm text-gray-700">{order.customerName}</p>
                            </div>
                            <span className={`px-2 py-1 rounded-full text-xs font-medium ${order.status === 'COMPLETED' ? 'bg-green-100 text-green-800' :
                                order.status === 'IN_PROGRESS' ? 'bg-blue-100 text-blue-800' :
                                    'bg-yellow-100 text-yellow-800'
                                }`}>
                                {order.status}
                            </span>
                        </div>

                        <div className="space-y-2 text-sm text-gray-800">
                            <div className="flex items-center gap-2">
                                <Calendar size={16} />
                                {new Date(order.date).toLocaleDateString()}
                            </div>
                            <div className="flex items-center gap-2">
                                <MapPin size={16} />
                                {order.location || "No location"}
                            </div>
                            <div className="flex items-center gap-2">
                                <User size={16} />
                                {order.workerName || (order.worker ? order.worker.name : "Unassigned")}
                            </div>
                            <div className="font-semibold text-gray-900 mt-2">
                                ₹{order.amount.toLocaleString()}
                            </div>
                            <div className="font-semibold text-blue-600 mt-1">
                                Worker: ₹{order.workerAmount?.toLocaleString() || "0"}
                            </div>
                        </div>

                        <div className="mt-4 pt-4 border-t border-gray-100 flex gap-2">
                            <button
                                onClick={() => setSelectedOrderId(order.id)}
                                className="flex-1 bg-gray-100 text-gray-700 py-2 rounded-md hover:bg-gray-200 text-sm font-medium"
                            >
                                Details & Payments
                            </button>
                            <button
                                onClick={() => setEditOrderId(order.id)}
                                className="flex-1 bg-blue-50 text-blue-700 py-2 rounded-md hover:bg-blue-100 text-sm font-medium"
                            >
                                Edit Order
                            </button>
                        </div>
                    </div>
                ))}
            </div>

            {isModalOpen && (
                <CreateOrderModal
                    workers={workers}
                    onClose={() => setIsModalOpen(false)}
                    onSuccess={() => {
                        setIsModalOpen(false);
                        fetchData();
                    }}
                />
            )}

            {editOrderId && (
                <EditOrderModal
                    order={orders.find(o => o.id === editOrderId)}
                    workers={workers}
                    onClose={() => setEditOrderId(null)}
                    onSuccess={() => {
                        setEditOrderId(null);
                        fetchData();
                    }}
                />
            )}

            {selectedOrder && (
                <OrderDetailsModal
                    order={selectedOrder}
                    onClose={() => setSelectedOrderId(null)}
                    onUpdate={fetchData}
                />
            )}
        </div>
    );
}

function CreateOrderModal({ workers, onClose, onSuccess }: any) {
    const [loading, setLoading] = useState(false);

    const handleSubmit = async (e: React.FormEvent<HTMLFormElement>) => {
        e.preventDefault();
        setLoading(true);

        const formData = new FormData(e.currentTarget);
        const data = Object.fromEntries(formData.entries());

        const workerId = formData.get("workerId") as string;
        let workerName = "";
        if (workerId) {
            const w = workers.find((w: any) => w.id === workerId);
            if (w) workerName = w.name;
        }

        try {
            await fetch("/api/order", {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({ ...data, workerName }),
            });
            onSuccess();
        } catch (err) {
            alert("Failed to create order");
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50">
            <div className="bg-white text-gray-900 rounded-lg p-6 w-full max-w-lg max-h-[90vh] overflow-y-auto">
                <h2 className="text-xl font-bold mb-4">Create New Order</h2>

                <form onSubmit={handleSubmit} className="space-y-4">
                    <div className="grid grid-cols-2 gap-4">
                        <div>
                            <label className="block text-sm font-medium text-gray-700">Customer Name</label>
                            <input name="customerName" required className="w-full p-2 border rounded-md" />
                        </div>
                        <div>
                            <label className="block text-sm font-medium text-gray-700">Order Name</label>
                            <input name="orderName" required className="w-full p-2 border rounded-md" />
                        </div>
                    </div>

                    <div className="grid grid-cols-2 gap-4">
                        <div>
                            <label className="block text-sm font-medium text-gray-700">Date</label>
                            <input name="date" type="date" required className="w-full p-2 border rounded-md" />
                        </div>
                        <div>
                            <label className="block text-sm font-medium text-gray-700">Amount</label>
                            <input name="amount" type="number" required className="w-full p-2 border rounded-md" />
                        </div>
                    </div>

                    <div className="grid grid-cols-2 gap-4">
                        <div>
                            <label className="block text-sm font-medium text-gray-700">Total Accessories (Count)</label>
                            <input name="totalAccessories" type="number" className="w-full p-2 border rounded-md" />
                        </div>
                        <div>
                            <label className="block text-sm font-medium text-gray-700">Ceremony Dates</label>
                            <input name="ceremonyDates" placeholder="e.g. 2023-10-01" className="w-full p-2 border rounded-md" />
                        </div>
                    </div>

                    <div>
                        <label className="block text-sm font-medium text-gray-700">Accessories Description</label>
                        <textarea name="accessories" className="w-full p-2 border rounded-md" rows={2} placeholder="List items..." />
                    </div>

                    <div>
                        <label className="block text-sm font-medium text-gray-700">Worker Amount</label>
                        <input name="workerAmount" type="number" className="w-full p-2 border rounded-md" />
                    </div>

                    <div>
                        <label className="block text-sm font-medium text-gray-700">Location</label>
                        <input name="location" className="w-full p-2 border rounded-md" />
                    </div>

                    <div>
                        <label className="block text-sm font-medium text-gray-700">Assign Worker</label>
                        <select name="workerId" className="w-full p-2 border rounded-md">
                            <option value="">Unassigned</option>
                            {workers.map((w: any) => (
                                <option key={w.id} value={w.id}>{w.name}</option>
                            ))}
                        </select>
                    </div>

                    <div className="flex justify-end gap-2 mt-6">
                        <button type="button" onClick={onClose} className="px-4 py-2 text-gray-800 hover:bg-gray-100 rounded-md">Cancel</button>
                        <button type="submit" disabled={loading} className="px-4 py-2 bg-blue-600 text-white rounded-md hover:bg-blue-700">Create Order</button>
                    </div>
                </form>
            </div>
        </div>
    );
}

function OrderDetailsModal({ order, onClose, onUpdate }: any) {
    const [loading, setLoading] = useState(false);

    // Parse accessories
    const accessoryItems = order.accessories ? order.accessories.split(',').map((s: string) => s.trim()).filter((s: string) => s) : [];
    const [selectedAccessoryItems, setSelectedAccessoryItems] = useState<string[]>(order.providedAccessoryItems || []);

    const accessoriesProvidedCount = selectedAccessoryItems.length;

    // Payment State
    const [payAmount, setPayAmount] = useState("");
    const [payDate, setPayDate] = useState(new Date().toISOString().split('T')[0]);
    const [payNote, setPayNote] = useState("");

    const totalPaid = order.amountPaid || 0;
    const balance = order.amount - totalPaid;
    const accessoriesLeft = (order.totalAccessories || 0) - accessoriesProvidedCount;

    const toggleAccessorycheck = async (item: string) => {
        const newSelected = selectedAccessoryItems.includes(item)
            ? selectedAccessoryItems.filter(i => i !== item)
            : [...selectedAccessoryItems, item];

        setSelectedAccessoryItems(newSelected);

        // Save immediately
        try {
            await fetch("/api/order", {
                method: "PUT",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({
                    id: order.id,
                    providedAccessoryItems: newSelected,
                }),
            });
            onUpdate();
        } catch (err) {
            alert("Failed to update accessories");
        }
    };

    const handleAddPayment = async (e: React.FormEvent) => {
        e.preventDefault();
        setLoading(true);
        try {
            await fetch("/api/order", {
                method: "PUT",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({
                    id: order.id,
                    newPayment: {
                        amount: parseFloat(payAmount),
                        date: payDate,
                        note: payNote
                    }
                }),
            });
            onUpdate();
        } catch (err) {
            alert("Failed to add payment");
            setLoading(false);
        }
    };

    const handleDeleteOrder = async () => {
        if (!confirm("Are you sure you want to delete this order PERMANENTLY?")) return;

        try {
            const res = await fetch(`/api/order?id=${order.id}`, { method: "DELETE" });
            if (res.ok) {
                onUpdate(); // This will re-fetch data
                onClose(); // Explicitly close since the order acts as "update" but now it's gone
            } else {
                alert("Failed to delete order");
            }
        } catch (err) {
            console.error(err);
            alert("Error deleting order");
        }
    };

    return (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50">
            <div className="bg-white text-gray-900 rounded-lg p-6 w-full max-w-2xl max-h-[90vh] overflow-y-auto">
                <div className="flex justify-between items-center mb-6">
                    <h2 className="text-xl font-bold">{order.orderName}</h2>
                    <div className="flex gap-2">
                        <button
                            onClick={handleDeleteOrder}
                            className="text-red-600 hover:text-red-800 p-2 rounded-md hover:bg-red-50 flex items-center gap-1 text-sm font-medium"
                        >
                            <Trash2 size={16} /> Delete
                        </button>
                        <button onClick={onClose} className="text-gray-700 hover:text-gray-900 px-3 py-1 bg-gray-100 rounded hover:bg-gray-200 text-sm">Close</button>
                    </div>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                    {/* Accessories Section */}
                    <div className="bg-gray-50 p-4 rounded-lg">
                        <h3 className="font-semibold text-lg mb-3">Accessories</h3>
                        <p className="text-sm text-gray-800 mb-2"><strong>Items:</strong> {order.accessories || "None"}</p>

                        <div className="space-y-3">
                            <div className="flex justify-between text-sm">
                                <span>Total Required:</span>
                                <span className="font-medium">{order.totalAccessories || 0}</span>
                            </div>
                            <div className="text-sm">
                                <div className="flex justify-between mb-2">
                                    <span>Provided ({accessoriesProvidedCount}):</span>
                                </div>
                                <div className="space-y-2 max-h-40 overflow-y-auto border p-2 rounded bg-white">
                                    {accessoryItems.length > 0 ? (
                                        accessoryItems.map((item: string, idx: number) => (
                                            <div key={idx} className="flex items-center gap-2">
                                                <input
                                                    type="checkbox"
                                                    id={`acc-${idx}`}
                                                    checked={selectedAccessoryItems.includes(item)}
                                                    onChange={() => toggleAccessorycheck(item)}
                                                    className="w-4 h-4 text-blue-600 rounded focus:ring-blue-500"
                                                />
                                                <label htmlFor={`acc-${idx}`} className="text-gray-900 cursor-pointer select-none">
                                                    {item}
                                                </label>
                                            </div>
                                        ))
                                    ) : (
                                        <p className="text-gray-500 italic text-xs">No individual items listed.</p>
                                    )}
                                </div>
                            </div>
                            <div className="flex justify-between text-sm border-t pt-2 mt-2">
                                <span className={accessoriesLeft > 0 ? "text-red-600 font-bold" : "text-green-600 font-bold"}>
                                    Left to Provide:
                                </span>
                                <span className={accessoriesLeft > 0 ? "text-red-600 font-bold" : "text-green-600 font-bold"}>
                                    {accessoriesLeft}
                                </span>
                            </div>
                        </div>
                    </div>

                    {/* Payment Section */}
                    <div className="bg-gray-50 p-4 rounded-lg">
                        <h3 className="font-semibold text-lg mb-3">Installment Payments</h3>
                        <div className="space-y-2 text-sm mb-4">
                            <div className="flex justify-between">
                                <span>Total Amount:</span>
                                <span>₹{order.amount.toLocaleString()}</span>
                            </div>
                            <div className="flex justify-between">
                                <span>Paid So Far:</span>
                                <span className="text-green-600">₹{totalPaid.toLocaleString()}</span>
                            </div>
                            <div className="flex justify-between font-bold border-t pt-2">
                                <span>Pending Balance:</span>
                                <span className={balance > 0 ? "text-red-600" : "text-green-600"}>₹{balance.toLocaleString()}</span>
                            </div>
                        </div>

                        <div className="mb-4 max-h-32 overflow-y-auto">
                            <h4 className="text-xs font-semibold text-gray-700 uppercase mb-2">History</h4>
                            {order.payments?.map((p: any, i: number) => (
                                <div key={i} className="flex justify-between text-xs py-1 border-b border-gray-100 last:border-0">
                                    <span>{new Date(p.date).toLocaleDateString()}</span>
                                    <span className="text-gray-700">{p.note}</span>
                                    <span className="font-medium">₹{p.amount.toLocaleString()}</span>
                                </div>
                            ))}
                            {(!order.payments || order.payments.length === 0) && <p className="text-xs text-gray-800">No payments yet.</p>}
                        </div>

                        <form onSubmit={handleAddPayment} className="space-y-2 border-t pt-3">
                            <h4 className="text-sm font-medium">Add Payment</h4>
                            <div className="grid grid-cols-2 gap-2">
                                <input
                                    type="number"
                                    placeholder="Amount"
                                    value={payAmount}
                                    onChange={(e) => setPayAmount(e.target.value)}
                                    required
                                    className="p-1 border rounded text-sm w-full"
                                />
                                <input
                                    type="date"
                                    value={payDate}
                                    onChange={(e) => setPayDate(e.target.value)}
                                    required
                                    className="p-1 border rounded text-sm w-full"
                                />
                            </div>
                            <input
                                type="text"
                                placeholder="Note (optional)"
                                value={payNote}
                                onChange={(e) => setPayNote(e.target.value)}
                                className="p-1 border rounded text-sm w-full"
                            />
                            <button
                                type="submit"
                                disabled={loading || !payAmount}
                                className="w-full bg-green-600 text-white py-1 rounded text-sm hover:bg-green-700 disabled:opacity-50"
                            >
                                Record Payment
                            </button>
                        </form>
                    </div>
                </div>
            </div>
        </div>
    );
}

function EditOrderModal({ order, workers, onClose, onSuccess }: any) {
    const [loading, setLoading] = useState(false);
    const [formData, setFormData] = useState({
        customerName: order.customerName,
        orderName: order.orderName,
        date: new Date(order.date).toISOString().split('T')[0],
        amount: order.amount,
        totalAccessories: order.totalAccessories || 0,
        ceremonyDates: order.ceremonyDates ? JSON.parse(order.ceremonyDates) : "",
        accessories: order.accessories || "",
        workerAmount: order.workerAmount || 0,
        location: order.location || "",
        workerId: order.workerId || ""
    });

    const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>) => {
        const { name, value } = e.target;
        setFormData(prev => ({ ...prev, [name]: value }));
    };

    const handleSubmit = async (e: React.FormEvent<HTMLFormElement>) => {
        e.preventDefault();
        setLoading(true);

        // Find worker name if workerId is selected
        let workerName = null;
        if (formData.workerId) {
            const w = workers.find((wk: any) => wk.id === formData.workerId);
            if (w) workerName = w.name;
        }

        const updateData = {
            id: order.id,
            ...formData,
            amount: parseFloat(formData.amount as string),
            totalAccessories: parseInt(formData.totalAccessories as string),
            workerAmount: parseFloat(formData.workerAmount as string),
            ceremonyDates: JSON.stringify(formData.ceremonyDates), // Needs to be stringified as per schema
            workerName
        };

        try {
            await fetch("/api/order", {
                method: "PUT",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify(updateData),
            });
            onSuccess();
        } catch (err) {
            alert("Failed to update order");
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50">
            <div className="bg-white text-gray-900 rounded-lg p-6 w-full max-w-lg max-h-[90vh] overflow-y-auto">
                <h2 className="text-xl font-bold mb-4">Edit Order</h2>

                <form onSubmit={handleSubmit} className="space-y-4">
                    <div className="grid grid-cols-2 gap-4">
                        <div>
                            <label className="block text-sm font-medium text-gray-700">Customer Name</label>
                            <input name="customerName" value={formData.customerName} onChange={handleChange} required className="w-full p-2 border rounded-md" />
                        </div>
                        <div>
                            <label className="block text-sm font-medium text-gray-700">Order Name</label>
                            <input name="orderName" value={formData.orderName} onChange={handleChange} required className="w-full p-2 border rounded-md" />
                        </div>
                    </div>

                    <div className="grid grid-cols-2 gap-4">
                        <div>
                            <label className="block text-sm font-medium text-gray-700">Date</label>
                            <input name="date" type="date" value={formData.date} onChange={handleChange} required className="w-full p-2 border rounded-md" />
                        </div>
                        <div>
                            <label className="block text-sm font-medium text-gray-700">Amount</label>
                            <input name="amount" type="number" value={formData.amount} onChange={handleChange} required className="w-full p-2 border rounded-md" />
                        </div>
                    </div>

                    <div className="grid grid-cols-2 gap-4">
                        <div>
                            <label className="block text-sm font-medium text-gray-700">Total Accessories (Count)</label>
                            <input name="totalAccessories" type="number" value={formData.totalAccessories} onChange={handleChange} className="w-full p-2 border rounded-md" />
                        </div>
                        <div>
                            <label className="block text-sm font-medium text-gray-700">Ceremony Dates</label>
                            <input name="ceremonyDates" placeholder="e.g. 2023-10-01" value={formData.ceremonyDates} onChange={handleChange} className="w-full p-2 border rounded-md" />
                        </div>
                    </div>

                    <div>
                        <label className="block text-sm font-medium text-gray-700">Accessories Description</label>
                        <textarea name="accessories" value={formData.accessories} onChange={handleChange} className="w-full p-2 border rounded-md" rows={2} placeholder="List items..." />
                    </div>

                    <div>
                        <label className="block text-sm font-medium text-gray-700">Worker Amount</label>
                        <input name="workerAmount" type="number" value={formData.workerAmount} onChange={handleChange} className="w-full p-2 border rounded-md" />
                    </div>

                    <div>
                        <label className="block text-sm font-medium text-gray-700">Location</label>
                        <input name="location" value={formData.location} onChange={handleChange} className="w-full p-2 border rounded-md" />
                    </div>

                    <div>
                        <label className="block text-sm font-medium text-gray-700">Assign Worker</label>
                        <select name="workerId" value={formData.workerId || ""} onChange={handleChange} className="w-full p-2 border rounded-md">
                            <option value="">Unassigned</option>
                            {workers.map((w: any) => (
                                <option key={w.id} value={w.id}>{w.name}</option>
                            ))}
                        </select>
                    </div>

                    <div className="flex justify-end gap-2 mt-6">
                        <button type="button" onClick={onClose} className="px-4 py-2 text-gray-800 hover:bg-gray-100 rounded-md">Cancel</button>
                        <button type="submit" disabled={loading} className="px-4 py-2 bg-blue-600 text-white rounded-md hover:bg-blue-700">Save Changes</button>
                    </div>
                </form>
            </div>
        </div>
    );
}

"use client";

import { useEffect, useState } from "react";
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, LineChart, Line } from "recharts";
import { Loader2, IndianRupee, ShoppingBag, Users, TrendingUp } from "lucide-react";

export default function AdminDashboard() {
    const [data, setData] = useState<any>(null);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState("");

    useEffect(() => {
        fetch("/api/dashboard")
            .then(async (res) => {
                const data = await res.json();
                if (!res.ok) {
                    throw new Error(data.error || "Failed to fetch data");
                }
                setData(data);
                setLoading(false);
            })
            .catch((err) => {
                console.error(err);
                setError(err.message);
                setLoading(false);
            });
    }, []);

    if (loading) {
        return (
            <div className="flex items-center justify-center h-full">
                <Loader2 className="animate-spin text-blue-600" size={32} />
            </div>
        );
    }

    if (error) {
        return (
            <div className="flex items-center justify-center h-full text-red-500">
                Error: {error}
            </div>
        );
    }

    if (!data) return <div>No data available</div>;

    return (
        <div className="space-y-6">
            <h1 className="text-2xl font-bold text-gray-900">Dashboard Overview</h1>

            {/* Stats Cards */}
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
                <StatCard
                    title="Total Revenue"
                    value={`₹${data.totalRevenue.toLocaleString()}`}
                    icon={IndianRupee}
                    color="bg-green-500"
                />
                <StatCard
                    title="Total Orders"
                    value={data.orderStats.total}
                    icon={ShoppingBag}
                    color="bg-blue-500"
                />
                <StatCard
                    title="Pending Orders"
                    value={data.orderStats.pending}
                    icon={Loader2}
                    color="bg-yellow-500"
                />
                <StatCard
                    title="Completed Orders"
                    value={data.orderStats.completed}
                    icon={TrendingUp}
                    color="bg-purple-500"
                />
            </div>

            {/* Charts */}
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
                <div className="bg-white p-6 rounded-lg shadow-sm border border-gray-200">
                    <h3 className="text-lg font-semibold mb-4">Sales Trends (Last 7 Days)</h3>
                    <div className="h-64 w-full">
                        <ResponsiveContainer width="100%" height="100%" minWidth={0}>
                            <LineChart data={data.salesTrends}>
                                <CartesianGrid strokeDasharray="3 3" />
                                <XAxis dataKey="date" />
                                <YAxis />
                                <Tooltip />
                                <Line type="monotone" dataKey="amount" stroke="#2563eb" strokeWidth={2} />
                            </LineChart>
                        </ResponsiveContainer>
                    </div>
                </div>

                <div className="bg-white p-6 rounded-lg shadow-sm border border-gray-200">
                    <h3 className="text-lg font-semibold mb-4">Revenue Split</h3>
                    <div className="flex items-center justify-center h-64 space-x-8">
                        <div className="text-center">
                            <div className="text-3xl font-bold text-green-600">₹{data.onlineRevenue.toLocaleString()}</div>
                            <div className="text-sm text-gray-700">Online</div>
                        </div>
                        <div className="h-16 w-px bg-gray-200"></div>
                        <div className="text-center">
                            <div className="text-3xl font-bold text-blue-600">₹{data.offlineRevenue.toLocaleString()}</div>
                            <div className="text-sm text-gray-700">Offline</div>
                        </div>
                    </div>
                </div>
            </div>

            {/* Worker Performance */}
            <div className="bg-white p-6 rounded-lg shadow-sm border border-gray-200">
                <h3 className="text-lg font-semibold mb-4">Worker Performance</h3>
                <div className="overflow-x-auto">
                    <table className="w-full text-sm text-left">
                        <thead className="text-xs text-gray-700 uppercase bg-gray-50">
                            <tr>
                                <th className="px-6 py-3">Worker Name</th>
                                <th className="px-6 py-3">Total Sales</th>
                                <th className="px-6 py-3">Completed Orders</th>
                                <th className="px-6 py-3">Pending Orders</th>
                            </tr>
                        </thead>
                        <tbody>
                            {data.workerPerformance.map((worker: any, idx: number) => (
                                <tr key={idx} className="bg-white border-b hover:bg-gray-50">
                                    <td className="px-6 py-4 font-medium text-gray-900">{worker.name}</td>
                                    <td className="px-6 py-4">₹{worker.totalSales.toLocaleString()}</td>
                                    <td className="px-6 py-4 text-green-600">{worker.completedOrders}</td>
                                    <td className="px-6 py-4 text-yellow-600">{worker.pendingOrders}</td>
                                </tr>
                            ))}
                        </tbody>
                    </table>
                </div>
            </div>
        </div>
    );
}

function StatCard({ title, value, icon: Icon, color }: any) {
    return (
        <div className="bg-white p-6 rounded-lg shadow-sm border border-gray-200 flex items-center justify-between">
            <div>
                <p className="text-sm font-medium text-gray-700">{title}</p>
                <h3 className="text-2xl font-bold text-gray-900 mt-1">{value}</h3>
            </div>
            <div className={`p-3 rounded-full ${color} bg-opacity-10`}>
                <Icon className={`text-${color.split('-')[1]}-600`} size={24} />
            </div>
        </div>
    );
}

"use client";

import { useEffect, useState } from "react";
import { Plus, Search, Trash2, Edit2 } from "lucide-react";
import { PRODUCT_CATEGORIES, PriceItem, PricingCategory } from "@/app/data/pricingData";

export default function ProductsPage() {
    const [products, setProducts] = useState<any[]>([]);
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [editProduct, setEditProduct] = useState<any | null>(null);

    const fetchProducts = () => {
        fetch("/api/product")
            .then(async (res) => {
                if (res.ok) return res.json();
                throw new Error("Failed to fetch products");
            })
            .then(setProducts)
            .catch(console.error);
    };

    const handleDelete = async (id: string) => {
        if (!confirm("Are you sure you want to delete this product sale?")) return;

        try {
            const res = await fetch(`/api/product?id=${id}`, { method: "DELETE" });
            if (res.ok) {
                fetchProducts();
            } else {
                alert("Failed to delete product");
            }
        } catch (err) {
            console.error(err);
            alert("Error deleting product");
        }
    };

    useEffect(() => {
        fetchProducts();
    }, []);

    return (
        <div className="space-y-6">
            <div className="flex items-center justify-between">
                <h1 className="text-2xl font-bold text-gray-900">Product Sales</h1>
                <button
                    onClick={() => setIsModalOpen(true)}
                    className="bg-blue-600 text-white px-4 py-2 rounded-md flex items-center gap-2 hover:bg-blue-700"
                >
                    <Plus size={20} />
                    Add Sale
                </button>
            </div>

            <div className="bg-white rounded-lg shadow-sm border border-gray-200 overflow-hidden">
                <table className="w-full text-sm text-left">
                    <thead className="text-xs text-gray-700 uppercase bg-gray-50">
                        <tr>
                            <th className="px-6 py-3">Date</th>
                            <th className="px-6 py-3">Customer</th>
                            <th className="px-6 py-3">Product</th>
                            <th className="px-6 py-3">Amount</th>
                            <th className="px-6 py-3">Payment</th>
                            <th className="px-6 py-3">Added By</th>
                            <th className="px-6 py-3 w-10"></th>
                        </tr>
                    </thead>
                    <tbody>
                        {products.map((product) => (
                            <tr key={product.id} className="bg-white border-b hover:bg-gray-50">
                                <td className="px-6 py-4">{new Date(product.date).toLocaleDateString()}</td>
                                <td className="px-6 py-4 font-medium text-gray-900">{product.customerName}</td>
                                <td className="px-6 py-4">{product.productName}</td>
                                <td className="px-6 py-4">₹{product.amount.toLocaleString()}</td>
                                <td className="px-6 py-4">
                                    <span className={`px-2 py-1 rounded-full text-xs ${product.paymentMethod === 'ONLINE' ? 'bg-green-100 text-green-800' : 'bg-gray-100 text-gray-800'
                                        }`}>
                                        {product.paymentMethod}
                                    </span>
                                </td>
                                <td className="px-6 py-4 text-gray-700">{product.createdBy?.name || 'Unknown'}</td>
                                <td className="px-6 py-4 flex items-center justify-end gap-2">
                                    <button
                                        onClick={() => setEditProduct(product)}
                                        className="text-blue-600 hover:text-blue-800 p-1 rounded-md hover:bg-blue-50"
                                        title="Edit Sale"
                                    >
                                        <Edit2 size={16} />
                                    </button>
                                    <button
                                        onClick={() => handleDelete(product.id)}
                                        className="text-red-600 hover:text-red-800 p-1 rounded-md hover:bg-red-50"
                                        title="Delete Sale"
                                    >
                                        <Trash2 size={16} />
                                    </button>
                                </td>
                            </tr>
                        ))}
                    </tbody>
                </table>
            </div>

            {isModalOpen && (
                <CreateProductModal
                    onClose={() => setIsModalOpen(false)}
                    onSuccess={() => {
                        setIsModalOpen(false);
                        fetchProducts();
                    }}
                />
            )}

            {editProduct && (
                <EditProductModal
                    product={editProduct}
                    onClose={() => setEditProduct(null)}
                    onSuccess={() => {
                        setEditProduct(null);
                        fetchProducts();
                    }}
                />
            )}
        </div>
    );
}



function CreateProductModal({ onClose, onSuccess }: any) {
    const [loading, setLoading] = useState(false);
    const [selectedCategory, setSelectedCategory] = useState<PricingCategory | null>(null);
    const [selectedItem, setSelectedItem] = useState<PriceItem | null>(null);
    const [quantity, setQuantity] = useState<number>(1);
    const [amount, setAmount] = useState<number>(0);

    // Update amount when item or quantity changes
    useEffect(() => {
        if (selectedItem) {
            setAmount(selectedItem.price * quantity);
        } else {
            setAmount(0);
        }
    }, [selectedItem, quantity]);

    const handleSubmit = async (e: React.FormEvent<HTMLFormElement>) => {
        e.preventDefault();
        setLoading(true);

        const formData = new FormData(e.currentTarget);
        const customerName = formData.get("customerName");
        const date = formData.get("date");
        const paymentMethod = formData.get("paymentMethod");

        if (!selectedCategory || !selectedItem) {
            alert("Please select a product category and item");
            setLoading(false);
            return;
        }

        // Construct product name
        const productName = `${selectedCategory.name} - ${selectedItem.name}${selectedCategory.variablePrice ? ':' : ' x'} ${quantity}${selectedCategory.variablePrice ? ' sq.in' : ''}`;

        const data = {
            customerName,
            productName,
            date,
            amount, // Use the calculated amount
            paymentMethod
        };

        try {
            await fetch("/api/product", {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify(data),
            });
            onSuccess();
        } catch (err) {
            alert("Failed to add product");
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50 overflow-y-auto">
            <div className="bg-white rounded-lg p-6 w-full max-w-md my-8">
                <h2 className="text-xl font-bold mb-4">Add New Sale</h2>

                <form onSubmit={handleSubmit} className="space-y-4">
                    <div>
                        <label className="block text-sm font-medium text-gray-700">Customer Name</label>
                        <input name="customerName" required className="w-full p-2 border rounded-md" />
                    </div>

                    {/* Category Selection */}
                    <div>
                        <label className="block text-sm font-medium text-gray-700">Category</label>
                        <select
                            className="w-full p-2 border rounded-md"
                            onChange={(e) => {
                                const category = PRODUCT_CATEGORIES.find(c => c.name === e.target.value) || null;
                                setSelectedCategory(category);
                                setSelectedItem(null);
                                setQuantity(1);
                            }}
                            required
                        >
                            <option value="">Select Category</option>
                            {PRODUCT_CATEGORIES.map(cat => (
                                <option key={cat.name} value={cat.name}>{cat.name}</option>
                            ))}
                        </select>
                    </div>

                    {/* Item Selection */}
                    <div>
                        <label className="block text-sm font-medium text-gray-700">Item</label>
                        <select
                            className="w-full p-2 border rounded-md"
                            onChange={(e) => {
                                const item = selectedCategory?.items.find(i => i.name === e.target.value) || null;
                                setSelectedItem(item);
                            }}
                            disabled={!selectedCategory}
                            required
                        >
                            <option value="">Select Item</option>
                            {selectedCategory?.items.map(item => (
                                <option key={item.name} value={item.name}>{item.name}</option>
                            ))}
                        </select>
                    </div>

                    <div className="grid grid-cols-2 gap-4">
                        <div>
                            <label className="block text-sm font-medium text-gray-700">
                                {selectedCategory?.variablePrice ? "Size (Sq. Inch)" : "Quantity"}
                            </label>
                            <input
                                type="number"
                                min="1"
                                value={quantity}
                                onChange={(e) => setQuantity(Number(e.target.value))}
                                className="w-full p-2 border rounded-md"
                                required
                            />
                        </div>
                        <div>
                            <label className="block text-sm font-medium text-gray-700">Amount (₹)</label>
                            <input
                                type="number"
                                value={amount}
                                onChange={(e) => setAmount(Number(e.target.value))}
                                className="w-full p-2 border rounded-md"
                            />
                        </div>
                    </div>

                    <div className="grid grid-cols-1 gap-4">
                        <div>
                            <label className="block text-sm font-medium text-gray-700">Date</label>
                            <input name="date" type="date" required className="w-full p-2 border rounded-md" />
                        </div>
                    </div>

                    <div>
                        <label className="block text-sm font-medium text-gray-700">Payment Method</label>
                        <div className="flex gap-4 mt-2">
                            <label className="flex items-center gap-2">
                                <input type="radio" name="paymentMethod" value="ONLINE" required /> Online
                            </label>
                            <label className="flex items-center gap-2">
                                <input type="radio" name="paymentMethod" value="OFFLINE" required /> Offline
                            </label>
                        </div>
                    </div>

                    <div className="flex justify-end gap-2 mt-6">
                        <button type="button" onClick={onClose} className="px-4 py-2 text-gray-800 hover:bg-gray-100 rounded-md">Cancel</button>
                        <button type="submit" disabled={loading} className="px-4 py-2 bg-blue-600 text-white rounded-md hover:bg-blue-700">Add Sale</button>
                    </div>
                </form>
            </div>
        </div>
    );
}

function EditProductModal({ product, onClose, onSuccess }: any) {
    const [loading, setLoading] = useState(false);
    const [formData, setFormData] = useState({
        customerName: product.customerName,
        productName: product.productName,
        date: new Date(product.date).toISOString().split('T')[0],
        amount: product.amount,
        paymentMethod: product.paymentMethod
    });

    const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        const { name, value } = e.target;
        setFormData(prev => ({ ...prev, [name]: value }));
    };

    const handleSubmit = async (e: React.FormEvent<HTMLFormElement>) => {
        e.preventDefault();
        setLoading(true);

        try {
            await fetch("/api/product", {
                method: "PUT",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({ ...formData, id: product.id }),
            });
            onSuccess();
        } catch (err) {
            alert("Failed to update product sale");
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50 overflow-y-auto">
            <div className="bg-white rounded-lg p-6 w-full max-w-md my-8">
                <h2 className="text-xl font-bold mb-4">Edit Sale</h2>

                <form onSubmit={handleSubmit} className="space-y-4">
                    <div>
                        <label className="block text-sm font-medium text-gray-700">Customer Name</label>
                        <input name="customerName" value={formData.customerName} onChange={handleChange} required className="w-full p-2 border rounded-md" />
                    </div>

                    <div>
                        <label className="block text-sm font-medium text-gray-700">Product Details</label>
                        <input name="productName" value={formData.productName} onChange={handleChange} required className="w-full p-2 border rounded-md" />
                    </div>

                    <div className="grid grid-cols-2 gap-4">
                        <div>
                            <label className="block text-sm font-medium text-gray-700">Amount (₹)</label>
                            <input
                                name="amount"
                                type="number"
                                value={formData.amount}
                                onChange={handleChange}
                                className="w-full p-2 border rounded-md"
                                required
                            />
                        </div>
                        <div>
                            <label className="block text-sm font-medium text-gray-700">Date</label>
                            <input name="date" type="date" value={formData.date} onChange={handleChange} required className="w-full p-2 border rounded-md" />
                        </div>
                    </div>

                    <div>
                        <label className="block text-sm font-medium text-gray-700">Payment Method</label>
                        <div className="flex gap-4 mt-2">
                            <label className="flex items-center gap-2">
                                <input type="radio" name="paymentMethod" value="ONLINE" checked={formData.paymentMethod === 'ONLINE'} onChange={handleChange} required /> Online
                            </label>
                            <label className="flex items-center gap-2">
                                <input type="radio" name="paymentMethod" value="OFFLINE" checked={formData.paymentMethod === 'OFFLINE'} onChange={handleChange} required /> Offline
                            </label>
                        </div>
                    </div>

                    <div className="flex justify-end gap-2 mt-6">
                        <button type="button" onClick={onClose} className="px-4 py-2 text-gray-800 hover:bg-gray-100 rounded-md">Cancel</button>
                        <button type="submit" disabled={loading} className="px-4 py-2 bg-blue-600 text-white rounded-md hover:bg-blue-700">Save Changes</button>
                    </div>
                </form>
            </div>
        </div>
    );
}

"use client";

import { useEffect, useState } from "react";
import { Plus, Search, User } from "lucide-react";

export default function WorkersPage() {
    const [workers, setWorkers] = useState<any[]>([]);
    const [loading, setLoading] = useState(true);
    const [isModalOpen, setIsModalOpen] = useState(false);

    const fetchWorkers = () => {
        fetch("/api/worker")
            .then((res) => res.json())
            .then((data) => {
                setWorkers(data);
                setLoading(false);
            });
    };

    useEffect(() => {
        fetchWorkers();
    }, []);

    return (
        <div className="space-y-6">
            <div className="flex items-center justify-between">
                <h1 className="text-2xl font-bold text-gray-900">Worker Management</h1>
                <button
                    onClick={() => setIsModalOpen(true)}
                    className="bg-blue-600 text-white px-4 py-2 rounded-md flex items-center gap-2 hover:bg-blue-700"
                >
                    <Plus size={20} />
                    Add Worker
                </button>
            </div>

            {/* Worker List */}
            <div className="bg-white rounded-lg shadow-sm border border-gray-200 overflow-hidden">
                <table className="w-full text-sm text-left">
                    <thead className="text-xs text-gray-700 uppercase bg-gray-50">
                        <tr>
                            <th className="px-6 py-3">Name</th>
                            <th className="px-6 py-3">Email</th>
                            <th className="px-6 py-3">Joined Date</th>
                            <th className="px-6 py-3">Assigned Orders</th>
                            <th className="px-6 py-3">Total Sales</th>
                            <th className="px-6 py-3">Actions</th>
                        </tr>
                    </thead>
                    <tbody>
                        {loading ? (
                            <tr>
                                <td colSpan={6} className="px-6 py-4 text-center">Loading...</td>
                            </tr>
                        ) : workers.length === 0 ? (
                            <tr>
                                <td colSpan={6} className="px-6 py-4 text-center text-gray-700">No workers found</td>
                            </tr>
                        ) : (
                            workers.map((worker) => (
                                <tr key={worker.id} className="bg-white border-b hover:bg-gray-50">
                                    <td className="px-6 py-4 font-medium text-gray-900 flex items-center gap-2">
                                        <div className="w-8 h-8 bg-gray-200 rounded-full flex items-center justify-center text-gray-800">
                                            <User size={16} />
                                        </div>
                                        {worker.name}
                                    </td>
                                    <td className="px-6 py-4">{worker.email}</td>
                                    <td className="px-6 py-4">{new Date(worker.createdAt).toLocaleDateString()}</td>
                                    <td className="px-6 py-4">{worker._count.assignedOrders}</td>
                                    <td className="px-6 py-4">{worker._count.sales}</td>
                                    <td className="px-6 py-4">
                                        <button className="text-red-600 hover:underline text-xs">Deactivate</button>
                                    </td>
                                </tr>
                            ))
                        )}
                    </tbody>
                </table>
            </div>

            {/* Create Worker Modal */}
            {isModalOpen && (
                <CreateWorkerModal
                    onClose={() => setIsModalOpen(false)}
                    onSuccess={() => {
                        setIsModalOpen(false);
                        fetchWorkers();
                    }}
                />
            )}
        </div>
    );
}

function CreateWorkerModal({ onClose, onSuccess }: any) {
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState("");

    const handleSubmit = async (e: React.FormEvent<HTMLFormElement>) => {
        e.preventDefault();
        setLoading(true);
        setError("");

        const formData = new FormData(e.currentTarget);
        const name = formData.get("name");
        const email = formData.get("email");
        const password = formData.get("password");

        try {
            const res = await fetch("/api/worker", {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({ name, email, password }),
            });

            if (!res.ok) throw new Error("Failed to create worker");

            onSuccess();
        } catch (err) {
            setError("Failed to create worker. Email might be in use.");
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50">
            <div className="bg-white rounded-lg p-6 w-full max-w-md">
                <h2 className="text-xl font-bold mb-4">Add New Worker</h2>

                <form onSubmit={handleSubmit} className="space-y-4">
                    {error && <div className="text-red-500 text-sm">{error}</div>}

                    <div>
                        <label className="block text-sm font-medium text-gray-700">Name</label>
                        <input name="name" required className="w-full p-2 border rounded-md" />
                    </div>

                    <div>
                        <label className="block text-sm font-medium text-gray-700">Email</label>
                        <input name="email" type="email" required className="w-full p-2 border rounded-md" />
                    </div>

                    <div>
                        <label className="block text-sm font-medium text-gray-700">Password</label>
                        <input name="password" type="password" required className="w-full p-2 border rounded-md" />
                    </div>

                    <div className="flex justify-end gap-2 mt-6">
                        <button
                            type="button"
                            onClick={onClose}
                            className="px-4 py-2 text-gray-800 hover:bg-gray-100 rounded-md"
                        >
                            Cancel
                        </button>
                        <button
                            type="submit"
                            disabled={loading}
                            className="px-4 py-2 bg-blue-600 text-white rounded-md hover:bg-blue-700 disabled:opacity-50"
                        >
                            {loading ? "Creating..." : "Create Worker"}
                        </button>
                    </div>
                </form>
            </div>
        </div>
    );
}

import { NextResponse } from "next/server";
import { getServerSession } from "next-auth";
import { authOptions } from "@/lib/auth";
import OpenAI from "openai";
import { createSale, createOrder, getRecentSales, getRecentOrders, updateSale, updateOrder, searchOrder } from "@/lib/ai-tools";

// Initialize Groq (via OpenAI SDK)
const groq = new OpenAI({
    apiKey: process.env.GROQ_API_KEY || "",
    baseURL: "https://api.groq.com/openai/v1",
});

export async function POST(req: Request) {
    const session = await getServerSession(authOptions);
    if (!session) return NextResponse.json({ error: "Unauthorized" }, { status: 401 });

    try {
        const { messages } = await req.json();

        const systemMessage = {
            role: "system",
            content: `You are a helpful inventory assistant for a photography studio. 
            You can add sales, create orders, check status, AND UPDATE existing items.
            Current Date: ${new Date().toISOString().split('T')[0]}
            Business ID: ${session.user.businessId}
            User ID: ${session.user.id}
            
            When adding items:
            - If payment method is not specified, ask. Default to OFFLINE if unsure but better to ask.
            - Format currency in INR (₹).

            UPDATES:
            - You can update an order by providing the Customer Name AND Order Name.
            - If multiple orders match the name, ask the user for clarification (by date).

            `
        };

        // Sanitize messages to remove 'id' which Groq rejects
        const cleanMessages = messages.map((m: any) => ({
            role: m.role,
            content: m.content,
            // Keep name for tool messages if necessary
            ...(m.name && { name: m.name }),
            ...(m.tool_calls && { tool_calls: m.tool_calls }),
            ...(m.tool_call_id && { tool_call_id: m.tool_call_id })
        }));

        const response = await groq.chat.completions.create({
            model: "llama-3.3-70b-versatile",
            messages: [systemMessage, ...cleanMessages],
            tools: [
                {
                    type: "function",
                    function: {
                        name: "create_sale",
                        description: "Record a new product sale",
                        parameters: {
                            type: "object",
                            properties: {
                                customerName: { type: "string" },
                                productName: { type: "string" },
                                amount: { type: "string", description: "Amount in INR" },
                                paymentMethod: { type: "string", enum: ["ONLINE", "OFFLINE"] },
                                date: { type: "string", description: "ISO date string YYYY-MM-DD" }
                            },
                            required: ["customerName", "productName", "amount", "paymentMethod", "date"]
                        }
                    }
                },
                {
                    type: "function",
                    function: {
                        name: "create_order",
                        description: "Create a new event order",
                        parameters: {
                            type: "object",
                            properties: {
                                customerName: { type: "string" },
                                orderName: { type: "string" },
                                amount: { type: "string", description: "Amount in INR" },
                                date: { type: "string", description: "ISO date string YYYY-MM-DD" },
                                location: { type: "string" },
                                workerAmount: { type: "string" },
                                accessories: { type: "string" }
                            },
                            required: ["customerName", "orderName", "amount", "date"]
                        }
                    }
                },
                {
                    type: "function",
                    function: {
                        name: "update_sale",
                        description: "Update an existing sale. Requires ID.",
                        parameters: {
                            type: "object",
                            properties: {
                                id: { type: "string", description: "The ID of the sale to update" },
                                customerName: { type: "string" },
                                productName: { type: "string" },
                                amount: { type: "string" },
                                paymentMethod: { type: "string", enum: ["ONLINE", "OFFLINE"] },
                                date: { type: "string" }
                            },
                            required: ["id"]
                        }
                    }
                },
                {
                    type: "function",
                    function: {
                        name: "update_order",
                        description: "Update an existing order. Requires ID.",
                        parameters: {
                            type: "object",
                            properties: {
                                originalDate: { type: "string", description: "Original date of the order to identify it if there are duplicates (YYYY-MM-DD)" },
                                customerName: { type: "string" },
                                orderName: { type: "string" },
                                amount: { type: "string" },
                                date: { type: "string" },
                                location: { type: "string" },
                                workerAmount: { type: "string" },
                                accessories: { type: "string" }
                            },
                            // Require either ID OR (Customer Name + Order Name) - enforcing loosely via prompt, code will validate
                            required: []
                        }
                    }
                },
                {
                    type: "function",
                    function: {
                        name: "get_recent_sales",
                        description: "Get list of recent sales",
                        parameters: {
                            type: "object",
                            properties: {
                                limit: { type: "string", description: "Number of items to return (default 5)" }
                            }
                        }
                    }
                },
                {
                    type: "function",
                    function: {
                        name: "get_recent_orders",
                        description: "Get recent orders",
                        parameters: {
                            type: "object",
                            properties: {
                                limit: { type: "string", description: "Number of items to return (default 5)" }
                            }
                        }
                    }
                },
                {
                    type: "function",
                    function: {
                        name: "search_order",
                        description: "Search for a specific order by name to view details",
                        parameters: {
                            type: "object",
                            properties: {
                                customerName: { type: "string" },
                                orderName: { type: "string" }
                            },
                            required: ["customerName", "orderName"]
                        }
                    }
                }
            ],
            tool_choice: "auto"
        });

        const responseMessage = response.choices[0].message;

        let toolCalls = responseMessage.tool_calls;

        // Fallback: Check for hallucinated tool calls in content
        if (!toolCalls && responseMessage.content) {
            // Robust broad match: capture everything between <function... and </function>
            // This handles variations like <function:name>, <function(name)>, etc.
            const broadMatch = responseMessage.content.match(/<function([\s\S]*?)<\/function>/);

            if (broadMatch) {
                try {
                    const rawContent = broadMatch[1]; // e.g., "(update_order)({...})" or ":update_order>{...}"

                    // 1. Extract Name: Find first alphanumeric sequence that looks like a function name
                    const nameMatch = rawContent.match(/([a-zA-Z0-9_]+)/);
                    if (!nameMatch) throw new Error("No function name found");
                    const functionName = nameMatch[1];

                    // 2. Extract JSON: Find the first '{' and try to parse from there
                    const jsonStartIndex = rawContent.indexOf('{');
                    const jsonEndIndex = rawContent.lastIndexOf('}');

                    if (jsonStartIndex === -1 || jsonEndIndex === -1) throw new Error("No JSON arguments found");

                    const jsonString = rawContent.substring(jsonStartIndex, jsonEndIndex + 1);
                    const functionArgs = JSON.parse(jsonString);

                    console.log("Detected hallucinated tool call (robust):", functionName);

                    toolCalls = [{
                        id: `call_${Date.now()}`,
                        type: 'function',
                        function: {
                            name: functionName,
                            arguments: JSON.stringify(functionArgs)
                        }
                    }];
                    // Clear content so the user doesn't see the raw code
                    responseMessage.content = null;
                } catch (e) {
                    console.error("Failed to parse hallucinated tool call:", e);
                }
            }
        }

        // Handle Tool Calls
        if (toolCalls) {

            const toolResults = await Promise.all(toolCalls.map(async (toolCall: any) => {
                const functionName = toolCall.function.name;
                const args = JSON.parse(toolCall.function.arguments);

                // Helper to parse amount safely
                const parseAmount = (val: any) => parseFloat(String(val).replace(/[^0-9.]/g, ''));
                // Helper to parse limit safely
                const parseLimit = (val: any) => val ? parseInt(String(val).replace(/[^0-9]/g, '')) : 5;

                let result;
                if (functionName === "create_sale") {
                    result = await createSale({
                        ...args,
                        amount: parseAmount(args.amount),
                        businessId: session.user.businessId,
                        userId: session.user.id
                    });
                } else if (functionName === "create_order") {
                    result = await createOrder({
                        ...args,
                        amount: parseAmount(args.amount),
                        workerAmount: args.workerAmount ? parseAmount(args.workerAmount) : undefined,
                        businessId: session.user.businessId
                    });
                } else if (functionName === "get_recent_sales") {
                    result = await getRecentSales(session.user.businessId, parseLimit(args.limit));
                } else if (functionName === "get_recent_orders") {
                    result = await getRecentOrders(session.user.businessId, parseLimit(args.limit));
                } else if (functionName === "update_sale") {
                    result = await updateSale(args.id, {
                        ...args,
                        amount: args.amount ? parseAmount(args.amount) : undefined
                    });
                } else if (functionName === "update_order") {
                    result = await updateOrder({
                        orderName: args.orderName,
                        customerName: args.customerName,
                        businessId: session.user.businessId,
                        date: args.originalDate
                    }, {
                        ...args,
                        amount: args.amount ? parseAmount(args.amount) : undefined,
                        workerAmount: args.workerAmount ? parseAmount(args.workerAmount) : undefined
                    });
                } else if (functionName === "search_order") {
                    result = await searchOrder(session.user.businessId, args.customerName, args.orderName);
                }

                return {
                    tool_call_id: toolCall.id,
                    role: "tool",
                    name: functionName,
                    content: JSON.stringify(result)
                };
            }));

            // Send tool results back to Grok to get final friendly message
            const finalResponse = await groq.chat.completions.create({
                model: "llama-3.3-70b-versatile",
                messages: [systemMessage, ...cleanMessages, responseMessage, ...toolResults as any]
            });

            return NextResponse.json({ content: finalResponse.choices[0].message.content });
        }

        return NextResponse.json({ content: responseMessage.content });

    } catch (error: any) {
        console.error("Chat API Error:", error);
        const keyStatus = process.env.GROQ_API_KEY ? `Key present (${process.env.GROQ_API_KEY.substring(0, 4)}...)` : "Key MISSING";
        return NextResponse.json({ error: `${error.message || "Internal Server Error"} | Debug: ${keyStatus}` }, { status: 500 });
    }
}

import { NextResponse } from "next/server";
import { db } from "@/lib/db";
import { getServerSession } from "next-auth";
import { authOptions } from "@/lib/auth";
import { startOfMonth, endOfMonth, startOfDay, endOfDay, subDays } from "date-fns";

export async function GET(req: Request) {
    const session = await getServerSession(authOptions);

    if (!session || session.user.role !== "ADMIN") {
        return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
    }

    try {
        const businessId = session.user.businessId;
        const now = new Date();

        // Fetch Products
        const productsSnapshot = await db.collection('products')
            .where('businessId', '==', businessId)
            .get();

        const products = productsSnapshot.docs.map(doc => {
            const data = doc.data();
            return {
                ...data,
                id: doc.id,
                // Convert Firestore Timestamps to Dates
                date: data.date.toDate ? data.date.toDate() : new Date(data.date),
                createdAt: data.createdAt?.toDate ? data.createdAt.toDate() : new Date(data.createdAt || now),
            };
        });

        // Total Revenue (Online vs Offline)
        const totalRevenue = products.reduce((acc, curr: any) => acc + (curr.amount || 0), 0);
        const onlineRevenue = products.filter((p: any) => p.paymentMethod === "ONLINE").reduce((acc, curr: any) => acc + (curr.amount || 0), 0);
        const offlineRevenue = products.filter((p: any) => p.paymentMethod === "OFFLINE").reduce((acc, curr: any) => acc + (curr.amount || 0), 0);

        // Sales Trends (Last 7 days)
        const salesTrends = [];
        for (let i = 6; i >= 0; i--) {
            const date = subDays(now, i);
            const start = startOfDay(date);
            const end = endOfDay(date);

            const daySales = products.filter((p: any) => p.date >= start && p.date <= end);
            salesTrends.push({
                date: date.toLocaleDateString(),
                amount: daySales.reduce((acc, curr: any) => acc + (curr.amount || 0), 0),
                count: daySales.length
            });
        }

        // Fetch Workers
        const workersSnapshot = await db.collection('users')
            .where('businessId', '==', businessId)
            .where('role', '==', 'WORKER')
            .get();

        const workers = workersSnapshot.docs.map(doc => ({ id: doc.id, ...doc.data() }));

        // Fetch Orders
        const ordersSnapshot = await db.collection('orders')
            .where('businessId', '==', businessId)
            .get();

        const orders = ordersSnapshot.docs.map(doc => ({ id: doc.id, ...doc.data() }));

        // Worker Performance
        // Note: In Firestore, we don't have "include" relations. We have to manually join.
        // We already have all products and orders for the business, so we can filter in memory.

        const workerPerformance = workers.map((w: any) => {
            // Sales by this worker (assuming products have createdById)
            const workerSales = products.filter((p: any) => p.createdById === w.id);

            // Orders assigned to this worker
            const workerOrders = orders.filter((o: any) => o.workerId === w.id);

            return {
                name: w.name,
                totalSales: workerSales.reduce((acc, curr: any) => acc + (curr.amount || 0), 0),
                completedOrders: workerOrders.filter((o: any) => o.status === "COMPLETED").length,
                pendingOrders: workerOrders.filter((o: any) => o.status === "PENDING").length
            };
        });

        // Order Stats
        const orderStats = {
            total: orders.length,
            pending: orders.filter((o: any) => o.status === "PENDING").length,
            completed: orders.filter((o: any) => o.status === "COMPLETED").length,
            inProgress: orders.filter((o: any) => o.status === "IN_PROGRESS").length
        };

        return NextResponse.json({
            totalRevenue,
            onlineRevenue,
            offlineRevenue,
            salesTrends,
            workerPerformance,
            orderStats
        });
    } catch (error) {
        console.error("Dashboard Error:", error);
        return NextResponse.json({ error: "Internal Server Error" }, { status: 500 });
    }
}

import { NextResponse } from "next/server";
import { db } from "@/lib/db";
import { getServerSession } from "next-auth";
import { authOptions } from "@/lib/auth";
import * as admin from "firebase-admin";

export async function POST(req: Request) {
    const session = await getServerSession(authOptions);

    if (!session || session.user.role !== "ADMIN") {
        return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
    }

    try {
        const body = await req.json();
        const { customerName, orderName, date, location, ceremonyDates, amount, workerAmount, workerId, workerName, accessories, totalAccessories } = body;

        const newOrder = {
            customerName,
            orderName,
            date: new Date(date),
            location,
            ceremonyDates: JSON.stringify(ceremonyDates),
            amount: parseFloat(amount),
            workerAmount: workerAmount ? parseFloat(workerAmount) : 0,
            workerId: workerId || null,
            workerName: workerName || null,
            accessories: accessories || "",
            totalAccessories: totalAccessories ? parseInt(totalAccessories) : 0,
            accessoriesProvided: 0,
            payments: [],
            amountPaid: 0,
            businessId: session.user.businessId,
            status: "PENDING",
            createdAt: new Date(),
            updatedAt: new Date()
        };

        const docRef = await db.collection('orders').add(newOrder);

        return NextResponse.json({ id: docRef.id, ...newOrder });
    } catch (error) {
        console.error(error);
        return NextResponse.json({ error: "Internal Server Error" }, { status: 500 });
    }
}

export async function GET(req: Request) {
    const session = await getServerSession(authOptions);

    if (!session) {
        return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
    }

    try {
        const ordersRef = db.collection('orders');
        const snapshot = await ordersRef.where('businessId', '==', session.user.businessId).get();

        let orders = snapshot.docs.map(doc => {
            const data = doc.data();
            return {
                id: doc.id,
                ...data,
                date: data.date.toDate ? data.date.toDate() : new Date(data.date),
                createdAt: data.createdAt?.toDate ? data.createdAt.toDate() : new Date(data.createdAt || new Date()),
                updatedAt: data.updatedAt?.toDate ? data.updatedAt.toDate() : new Date(data.updatedAt || new Date()),
            };
        });

        if (session.user.role === "WORKER") {
            orders = orders.filter((o: any) => o.workerId === session.user.id || o.workerId === null);
        }

        // Sort by date desc
        orders.sort((a: any, b: any) => b.date.getTime() - a.date.getTime());

        return NextResponse.json(orders);
    } catch (error) {
        console.error("Get Orders Error:", error);
        return NextResponse.json({ error: "Internal Server Error" }, { status: 500 });
    }
}

export async function PUT(req: Request) {
    const session = await getServerSession(authOptions);
    if (!session) return NextResponse.json({ error: "Unauthorized" }, { status: 401 });

    try {
        const { id, status, workerId, ...updates } = await req.json();

        const orderRef = db.collection('orders').doc(id);
        const orderDoc = await orderRef.get();

        if (!orderDoc.exists) {
            return NextResponse.json({ error: "Not found" }, { status: 404 });
        }

        const order = orderDoc.data() as any;

        if (session.user.role === "WORKER") {
            if (order.workerId && order.workerId !== session.user.id) {
                return NextResponse.json({ error: "Not authorized to edit this order" }, { status: 403 });
            }
            // If worker is claiming, allow workerId update
            if (workerId && !order.workerId) {
                updates.workerId = workerId;
            }
        } else {
            // Admin can update workerId freely
            if (workerId !== undefined) {
                updates.workerId = workerId;
            }
        }

        const updateData: any = {
            ...updates,
            updatedAt: new Date()
        };
        if (status) updateData.status = status;

        // Remove undefined fields
        Object.keys(updateData).forEach(key => updateData[key] === undefined && delete updateData[key]);

        // Check for new payment
        if (updates.newPayment) {
            updateData.payments = admin.firestore.FieldValue.arrayUnion(updates.newPayment);
            updateData.amountPaid = admin.firestore.FieldValue.increment(updates.newPayment.amount);
            delete updateData.newPayment;
        }

        // Handle providedAccessoryItems update
        if (updates.providedAccessoryItems) {
            updateData.providedAccessoryItems = updates.providedAccessoryItems;
            updateData.accessoriesProvided = updates.providedAccessoryItems.length;
        }

        await orderRef.update(updateData);
        return NextResponse.json({ id, ...order, ...updateData });

    } catch (error) {
        console.error("Update Order Error:", error);
        return NextResponse.json({ error: "Internal Server Error" }, { status: 500 });
    }
}

export async function DELETE(req: Request) {
    const session = await getServerSession(authOptions);
    if (!session || session.user.role !== "ADMIN") {
        return NextResponse.json({ error: "Unauthorized" }, { status: 403 });
    }

    try {
        const { searchParams } = new URL(req.url);
        const id = searchParams.get("id");

        if (!id) return NextResponse.json({ error: "Missing ID" }, { status: 400 });

        await db.collection('orders').doc(id).delete();

        return NextResponse.json({ success: true });
    } catch (error) {
        console.error("Delete Order Error:", error);
        return NextResponse.json({ error: "Internal Server Error" }, { status: 500 });
    }
}

